import React, { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import axios from "axios";

export default function VehicleDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [vehicle, setVehicle] = useState(null);
  const [loading, setLoading] = useState(true);
  const [selectedImageIndex, setSelectedImageIndex] = useState(0);
  const [error, setError] = useState("");
  const [imageErrors, setImageErrors] = useState({});

  useEffect(() => {
    const fetchVehicle = async () => {
      try {
        setLoading(true);
        setError("");
        const res = await axios.get(`http://localhost:8070/api/vehicles`);
        const found = res.data.find((v) => v._id === id);
        if (!found) {
          setError("Vehicle not found");
          return;
        }
        setVehicle(found);
      } catch (err) {
        setError(err.response?.data?.message || "Failed to load vehicle details");
      } finally {
        setLoading(false);
      }
    };

    fetchVehicle();
  }, [id]);

  // Auto-rotate images
  useEffect(() => {
    if (!vehicle || !vehicle.images || vehicle.images.length <= 1) {
      return;
    }

    const interval = setInterval(() => {
      setSelectedImageIndex(prev => (prev + 1) % vehicle.images.length);
    }, 5000);

    return () => clearInterval(interval);
  }, [vehicle]);

  const handleImageError = (index) => {
    setImageErrors(prev => ({
      ...prev,
      [index]: true
    }));
  };

  if (loading) {
    return (
      <div className="page" style={{ textAlign: "center", padding: "60px 20px" }}>
        <div style={{ color: "var(--text-light)", fontSize: "16px" }}>Loading vehicle details...</div>
      </div>
    );
  }

  if (error || !vehicle) {
    return (
      <div className="page" style={{ textAlign: "center", padding: "60px 20px" }}>
        <div style={{ color: "var(--text-light)", fontSize: "16px", marginBottom: 24 }}>
          {error || "Vehicle not found"}
        </div>
        <button onClick={() => navigate("/")} className="btn btnPrimary">
          Back to Home
        </button>
      </div>
    );
  }

  const mainImage = vehicle.images?.[selectedImageIndex]?.url || `https://via.placeholder.com/600x400?text=${vehicle.brand}`;

  return (
    <div style={{ backgroundColor: "var(--bg)", minHeight: "100vh" }}>
      <div className="page" style={{ maxWidth: "1200px", margin: "0 auto", padding: "40px 20px" }}>
        {/* Back Button */}
        <button 
          onClick={() => navigate("/")} 
          style={{
            background: "none",
            border: "none",
            color: "var(--primary)",
            cursor: "pointer",
            fontSize: "14px",
            fontWeight: 600,
            marginBottom: 24,
            padding: 0,
            display: "flex",
            alignItems: "center",
            gap: 6
          }}
        >
          ← Back to Vehicles
        </button>

        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 40, alignItems: "start" }}>
          {/* Images Section */}
          <div>
            {/* Main Image */}
            <div style={{
              width: "100%",
              height: "400px",
              backgroundColor: "#f0f0f0",
              borderRadius: "8px",
              overflow: "hidden",
              marginBottom: 16,
              display: "flex",
              alignItems: "center",
              justifyContent: "center"
            }}>
              {imageErrors[selectedImageIndex] ? (
                <div style={{
                  width: "100%",
                  height: "100%",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  backgroundColor: "#e0e0e0",
                  color: "#999",
                  fontSize: "16px"
                }}>
                  Image Not Available
                </div>
              ) : (
                <img
                  src={mainImage}
                  alt={`${vehicle.brand} ${vehicle.type}`}
                  onError={() => handleImageError(selectedImageIndex)}
                  style={{
                    width: "100%",
                    height: "100%",
                    objectFit: "cover"
                  }}
                />
              )}
            </div>

            {/* Thumbnail Gallery */}
            {vehicle.images && vehicle.images.length > 1 && (
              <div style={{
                display: "grid",
                gridTemplateColumns: "repeat(auto-fit, minmax(100px, 1fr))",
                gap: 12
              }}>
                {vehicle.images.map((img, idx) => (
                  <div
                    key={idx}
                    onClick={() => setSelectedImageIndex(idx)}
                    style={{
                      width: "100%",
                      height: "100px",
                      backgroundColor: "#f0f0f0",
                      borderRadius: "6px",
                      overflow: "hidden",
                      cursor: "pointer",
                      border: selectedImageIndex === idx ? "3px solid var(--primary)" : "2px solid transparent",
                      transition: "all 0.3s ease"
                    }}
                    onMouseEnter={(e) => e.currentTarget.style.transform = "scale(1.05)"}
                    onMouseLeave={(e) => e.currentTarget.style.transform = "scale(1)"}
                  >
                    {imageErrors[idx] ? (
                      <div style={{
                        width: "100%",
                        height: "100%",
                        display: "flex",
                        alignItems: "center",
                        justifyContent: "center",
                        backgroundColor: "#e0e0e0",
                        color: "#999",
                        fontSize: "12px"
                      }}>
                        N/A
                      </div>
                    ) : (
                      <img
                        src={img.url}
                        alt={`${vehicle.brand} view ${idx + 1}`}
                        onError={() => handleImageError(idx)}
                        style={{
                          width: "100%",
                          height: "100%",
                          objectFit: "cover"
                        }}
                      />
                    )}
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* Details Section */}
          <div>
            {/* Title */}
            <div style={{ marginBottom: 24 }}>
              <h1 style={{
                fontSize: "36px",
                fontWeight: 700,
                color: "var(--text)",
                margin: "0 0 8px 0"
              }}>
                {vehicle.brand}
              </h1>
              <div style={{
                fontSize: "18px",
                color: "var(--text-light)",
                fontWeight: 500
              }}>
                {vehicle.type} • {vehicle.year}
              </div>
            </div>

            {/* Status Badge */}
            <div style={{
              display: "inline-block",
              backgroundColor: vehicle.status === "available" ? "rgba(76, 175, 80, 0.1)" : "rgba(244, 67, 54, 0.1)",
              color: vehicle.status === "available" ? "var(--primary)" : "#f44336",
              padding: "8px 16px",
              borderRadius: "6px",
              fontSize: "13px",
              fontWeight: 600,
              textTransform: "capitalize",
              marginBottom: 24
            }}>
              {vehicle.status || "Available"}
            </div>

            {/* Price */}
            <div className="card cardPad" style={{ marginBottom: 24, backgroundColor: "rgba(76, 175, 80, 0.05)", borderLeft: "4px solid var(--primary)" }}>
              <div style={{ fontSize: "12px", color: "var(--text-light)", fontWeight: 600, textTransform: "uppercase", marginBottom: 8 }}>
                Price
              </div>
              <div style={{
                fontSize: "32px",
                fontWeight: 700,
                color: "var(--primary)"
              }}>
                LKR {Number(vehicle.price || 0).toLocaleString()}
              </div>
            </div>

            {/* Vehicle Details Grid */}
            <div style={{
              display: "grid",
              gridTemplateColumns: "1fr 1fr",
              gap: 16,
              marginBottom: 32
            }}>
              <DetailBox label="Brand" value={vehicle.brand} />
              <DetailBox label="Type" value={vehicle.type} />
              <DetailBox label="Year" value={vehicle.year} />
              <DetailBox label="Status" value={vehicle.status || "Available"} />
              <DetailBox 
                label="Vehicle Number" 
                value={vehicle.vehicleNumber || "-"} 
                colspan={2}
              />
            </div>

            {/* Description */}
            {vehicle.details && (
              <div className="card cardPad" style={{ marginBottom: 32 }}>
                <div style={{
                  fontSize: "12px",
                  color: "var(--text-light)",
                  fontWeight: 600,
                  textTransform: "uppercase",
                  marginBottom: 12
                }}>
                  Description
                </div>
                <div style={{
                  fontSize: "15px",
                  color: "var(--text)",
                  lineHeight: 1.6,
                  whiteSpace: "pre-wrap"
                }}>
                  {vehicle.details}
                </div>
              </div>
            )}

            {/* Action Buttons */}
            <div style={{ display: "flex", gap: 12, flexWrap: "wrap" }}>
              <button
                onClick={() => navigate("/book-appointment", { state: { vehicleId: vehicle._id } })}
                className="btn btnPrimary"
                style={{ flex: 1, minWidth: 150 }}
              >
                Book Test Drive
              </button>
              <button
                onClick={() => navigate("/")}
                className="btn"
                style={{ flex: 1, minWidth: 150 }}
              >
                Back to Browse
              </button>
            </div>
          </div>
        </div>

        {/* Responsive Mobile Layout */}
        {/* On mobile, this will stack vertically due to grid-template-columns adjustment */}
      </div>

      <style>{`
        @media (max-width: 768px) {
          .vehicle-detail-grid {
            grid-template-columns: 1fr !important;
          }
        }
      `}</style>
    </div>
  );
}

function DetailBox({ label, value, colspan }) {
  return (
    <div className="card cardPad" style={{
      gridColumn: colspan ? `span ${colspan}` : "span 1"
    }}>
      <div style={{
        fontSize: "12px",
        color: "var(--text-light)",
        fontWeight: 600,
        textTransform: "uppercase",
        marginBottom: 8
      }}>
        {label}
      </div>
      <div style={{
        fontSize: "16px",
        fontWeight: 600,
        color: "var(--text)"
      }}>
        {value}
      </div>
    </div>
  );
}
